CONNECTION POOL IMPLEMENTATION:

```typescript
interface PoolConfig<T> {
  minConnections: number;
  maxConnections: number;
  acquireTimeout: number;
  idleTimeout: number;
  validateConnection?: (conn: T) => Promise<boolean>;
  createConnection: () => Promise<T>;
  destroyConnection: (conn: T) => Promise<void>;
}

interface PoolMetrics {
  poolSize: number;
  idleCount: number;
  inUseCount: number;
  waitQueueLength: number;
  totalCreated: number;
  totalDestroyed: number;
}

interface PoolEntry<T> {
  conn: T;
  lastUsed: number;
}

export class ConnectionPool<T> {
  private config: PoolConfig<T>;
  private idleConnections: PoolEntry<T>[] = [];
  private inUseConnections: Set<T> = new Set();
  private waitQueue: Array<{
    resolve: (conn: T) => void;
    reject: (err: Error) => void;
    timeout: NodeJS.Timeout;
  }> = [];
  private metrics: PoolMetrics = {
    poolSize: 0,
    idleCount: 0,
    inUseCount: 0,
    waitQueueLength: 0,
    totalCreated: 0,
    totalDestroyed: 0,
  };
  private isShuttingDown = false;
  private reaperInterval: NodeJS.Timeout | null = null;

  constructor(config: PoolConfig<T>) {
    this.config = config;
    this.startIdleReaper();
    this.initializeMinConnections();
  }

  private async initializeMinConnections(): Promise<void> {
    for (let i = 0; i < this.config.minConnections; i++) {
      try {
        const conn = await this.createConnection();
        this.idleConnections.push({ conn, lastUsed: Date.now() });
      } catch (err) {
        console.error('Failed to create initial connection:', err);
      }
    }
    this.updateMetrics();
  }

  private async createConnection(): Promise<T> {
    const conn = await this.config.createConnection();
    this.metrics.poolSize++;
    this.metrics.totalCreated++;
    return conn;
  }

  private async destroyConnection(conn: T): Promise<void> {
    await this.config.destroyConnection(conn);
    this.metrics.poolSize--;
    this.metrics.totalDestroyed++;
  }

  async acquire(): Promise<T> {
    if (this.isShuttingDown) {
      throw new Error('Pool is shutting down');
    }

    // Try idle connection first
    const idle = this.idleConnections.pop();
    if (idle) {
      if (this.config.validateConnection) {
        const isValid = await this.config.validateConnection(idle.conn);
        if (!isValid) {
          await this.destroyConnection(idle.conn);
          return this.acquire();
        }
      }
      this.inUseConnections.add(idle.conn);
      this.updateMetrics();
      return idle.conn;
    }

    // Create new if under max
    if (this.metrics.poolSize < this.config.maxConnections) {
      const conn = await this.createConnection();
      this.inUseConnections.add(conn);
      this.updateMetrics();
      return conn;
    }

    // Queue the request
    return new Promise<T>((resolve, reject) => {
      const timeout = setTimeout(() => {
        this.removeFromQueue(timeout);
        reject(new Error('Connection acquire timeout'));
      }, this.config.acquireTimeout);
      this.waitQueue.push({ resolve, reject, timeout });
      this.updateMetrics();
    });
  }

  async release(conn: T): Promise<void> {
    if (!this.inUseConnections.delete(conn)) {
      return;
    }

    if (this.isShuttingDown) {
      await this.destroyConnection(conn);
      this.checkShutdown();
      return;
    }

    // Give to next waiter
    const waiter = this.waitQueue.shift();
    if (waiter) {
      clearTimeout(waiter.timeout);
      this.inUseConnections.add(conn);
      waiter.resolve(conn);
      this.updateMetrics();
      return;
    }

    // Return to idle
    this.idleConnections.push({ conn, lastUsed: Date.now() });
    this.updateMetrics();
  }

  private removeFromQueue(timeout: NodeJS.Timeout): void {
    const idx = this.waitQueue.findIndex(w => w.timeout === timeout);
    if (idx !== -1) {
      this.waitQueue.splice(idx, 1);
      this.updateMetrics();
    }
  }

  private startIdleReaper(): void {
    this.reaperInterval = setInterval(() => {
      const now = Date.now();
      const toRemove: T[] = [];
      for (const item of this.idleConnections) {
        if (
          now - item.lastUsed > this.config.idleTimeout &&
          this.metrics.poolSize > this.config.minConnections
        ) {
          toRemove.push(item.conn);
        }
      }
      for (const conn of toRemove) {
        const idx = this.idleConnections.findIndex(i => i.conn === conn);
        if (idx !== -1) {
          this.idleConnections.splice(idx, 1);
          this.destroyConnection(conn);
        }
      }
      this.updateMetrics();
    }, Math.min(this.config.idleTimeout, 30000));
  }

  async shutdown(): Promise<void> {
    this.isShuttingDown = true;
    if (this.reaperInterval) {
      clearInterval(this.reaperInterval);
    }
    for (const waiter of this.waitQueue) {
      clearTimeout(waiter.timeout);
      waiter.reject(new Error('Pool shutting down'));
    }
    this.waitQueue = [];
    for (const item of this.idleConnections) {
      await this.destroyConnection(item.conn);
    }
    this.idleConnections = [];
    await this.checkShutdown();
  }

  private async checkShutdown(): Promise<void> {
    if (this.isShuttingDown && this.inUseConnections.size === 0) {
      // Shutdown complete
    }
  }

  private updateMetrics(): void {
    this.metrics.idleCount = this.idleConnections.length;
    this.metrics.inUseCount = this.inUseConnections.size;
    this.metrics.waitQueueLength = this.waitQueue.length;
  }

  getMetrics(): PoolMetrics {
    return { ...this.metrics };
  }
}
```

Features: Generic type T, min/max connections, acquire/idle timeouts, health validation, auto-scaling, idle reaping, request queue, graceful shutdown, full metrics.
